export const getActiveServices = (): Service[] => mockServices.filter(service => service.isActive);
export const getServiceById = (id: string): Service | undefined => mockServices.find(service => service.id === id);
export const getServicesByCategory = (category: ServiceCategory): Service[] =>
  mockServices.filter(service => service.category === category);
